(150, '_transient_feed_9bbd59226dc36b9b26cd43f15694c5c3', 'a:4:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:52:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\n \n	\n		\n		\n		\n		\n		\n		\n		\n		\n		\n	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:8:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"WordPress News\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://wordpress.org/news\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"The latest news about WordPress and the WordPress community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:13:\"lastBuildDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 12 Jan 2024 16:58:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"en-US\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"generator\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"https://wordpress.org/?v=6.5-alpha-57289\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"image\";a:1:{i:0;a:6:{s:4:\"data\";s:11:\"\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:3:\"url\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"https://s.w.org/favicon.ico?2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"WordPress News\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://wordpress.org/news\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"Data Liberation in 2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://wordpress.org/news/2024/01/data-liberation-in-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 12 Jan 2024 16:58:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16736\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:314:\"Imagine a more open web where people can switch between any platform of their choosing. A web where being locked into a system is a thing of the past. This is the web I’ve always wanted to see. That’s why I announced a new initiative called Data Liberation for 2024. Migrating your site to WordPress, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Matt Mullenweg\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2885:\"\n<p>Imagine a more open web where people can switch between any platform of their choosing. A web where being locked into a system is a thing of the past. This is the web I’ve always wanted to see. That’s why I announced a new initiative called <a href=\"https://wordpress.org/data-liberation/\" target=\"_blank\" rel=\"noreferrer noopener\">Data Liberation</a> for 2024. Migrating your site to WordPress, or exporting all your content from WordPress, should be possible in one click. I want WordPress’ export format to become the lingua franca of CMSes, whether coming to WordPress or moving within WordPress. </p>\n\n\n\n<p>I often hear about folks across the WordPress community duplicating efforts when creating scripts and workflows to move users to WordPress. Imagine if we shared those resources instead and built community-owned plugins that anyone could use! </p>\n\n\n\n<p>But it should be more than plugins; workflows, tutorials, and helper scripts should be shared, too. I want this resource to have space to include moving from social networks, moving from a page builder to core blocks, switching from classic to blocks, and improving WordPress current canonical plugins for importing. </p>\n\n\n\n<h2 class=\"wp-block-heading\">You can help!</h2>\n\n\n\n<p>Of course, the heart of any open source project is the community that shows up to build it. My hope is that this marks the start of a new contribution pathway, separate from core teams, that allows folks to contribute what they’ve learned and what they’ve created to help others move to WordPress. I expect this emphasis on migration will also influence future development, both in core and with recommended community or canonical plugins.</p>\n\n\n\n<p>There are a few things that I think will be key to making this project a success:</p>\n\n\n\n<ul>\n<li>A dedicated landing page on WordPress.org following a WordPress.org/and/[platform-name] format.</li>\n\n\n\n<li>A forum used for non-review user feedback and general discussion.</li>\n\n\n\n<li>A dedicated Slack channel.</li>\n\n\n\n<li>Moderation within hours rather than days.</li>\n\n\n\n<li>Listed on <a href=\"https://github.com/WordPress\">WordPress GitHub</a> with syncing for individual commits to SVN for history in both places.</li>\n</ul>\n\n\n\n<p>By complementing the community’s existing efforts—the <a href=\"https://wordpress.org/five-for-the-future/\">Five for the Future program</a>, the <a href=\"https://learn.wordpress.org/\">Learn WordPress initiative</a>, a focus on internationalization, etc.—my hope is that this will help even more people see themselves in the WordPress project, providing fresh momentum for <a href=\"https://events.wordpress.org/\">WordCamps and meetups</a>. </p>\n\n\n\n<p>It’s never been more crucial to champion openness on the web. Bringing focused attention to improved portability will untether users and increase their freedom like never before.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16736\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WP Briefing: Episode 70: A Look Ahead at WordPress in 2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://wordpress.org/news/2024/01/episode-70-a-look-ahead-at-wordpress-in-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 08 Jan 2024 13:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=16677\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:264:\"Curious about WordPress\'s big-picture items for 2024? Phase 3, Data Liberation, new meetups, and more, get the spotlight in this episode. Join Executive Director Josepha Haden Chomphosy for all this, plus a small list of big things coming up in the next two weeks.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:50:\"https://wordpress.org/news/files/2024/01/WP070.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8342:\"\n<p>Curious about WordPress&#8217;s big-picture items for 2024? Phase 3, Data Liberation, new meetups, and more, get the spotlight in this episode. Join Executive Director Josepha Haden Chomphosy for all this, plus a small list of big things coming up in the next two weeks.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/07/03/real-time-collaboration/\">Real-Time Collaboration</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/\">Make WordPress Core</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/data-liberation/\">Data Liberation</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/plugins/\">Make WordPress Plugins</a></li>\n\n\n\n<li><a href=\"https://events.wordpress.org/\">WordCamp Events</a></li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul>\n<li><a href=\"https://make.wordpress.org/project/2023/12/12/overflow-questions-from-state-of-the-word-2023/\">Overflow Questions from State of the Word 2023 in Madrid, Spain</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2023/11/17/announcing-the-2023-annual-meetup-survey/\" target=\"_blank\" rel=\"noreferrer noopener\">Annual Meetup Survey</a>&nbsp;&#8211; This is the final chance to share your feedback on WordPress meetups for 2024 and how we can improve the program in the future.&nbsp;</li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcripts</h2>\n\n\n\n<span id=\"more-16677\"></span>\n\n\n\n<p>[00:00:00] <strong>Josepha:</strong> Hello, everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I&#8217;m your host, Josepha Haden Chomphosy. Here we go.&nbsp;</p>\n\n\n\n<p>[00:00:28] (Intro music)&nbsp;</p>\n\n\n\n<p>[00:00:40] <strong>Josepha:</strong> Hello, my dears, and welcome to 2024. I hope you&#8217;ve had a lovely break. At the top of the year, I like to look around and gather the projects that the community is interested in. We can&#8217;t always commit to everything, and sometimes even the things we plan to do can&#8217;t make it across the finish line. In the next few weeks, I&#8217;ll be publishing kind of the big picture goals for the year, but I wanted to share a little bit about what I&#8217;ve collected so far.</p>\n\n\n\n<p>[00:01:05] <strong>Josepha:</strong> Firstly, we&#8217;ve got Phase 3. This has been called a few things over the years: collaborative editing, multiplayer, co-editing. But whatever it&#8217;s been called, the biggest changes to writing and design workflows are likely to happen in this phase. A redesigned workflow can be a bit of a shock. But fortunately, we already have a prototype out there.</p>\n\n\n\n<p>I&#8217;ll include a link to some resources in the show notes, or of course, you can always stop by make.WordPress.org/core for some insights. But I would encourage you to, at the very least, get your hands on that prototype to see what it looks like is coming in Phase 3 so that you can be aware and provide your feedback.</p>\n\n\n\n<p>The next thing on our list is Data Liberation. This is a new-to-us project that was introduced at State of the Word. Fortunately, though, it&#8217;s not a new concept overall. Data Liberation is actually one of the earliest ideas that sold me on WordPress. The idea that you could set up a site for a client, or yourself, and that hard work wasn&#8217;t lost if something went wrong, was really important to me. It&#8217;s been a long time since we put any effort into our importers and exporters, and I think this will be a good focus for the year.</p>\n\n\n\n<p>[00:02:14] <strong>Josepha:</strong> The next thing that I&#8217;ve picked up, kind of a list of three things, but there are three mid-sized areas that I want us to pay attention to this year: plugins, old tickets, and new meetups.&nbsp;</p>\n\n\n\n<p>Plugins, because they really have turned a corner on where they ended 2023. A lot of work has been done to make sure that they&#8217;ve streamlined some efforts, gotten some better onboarding for folks as they&#8217;re going in, and we could really use a hand to keep that momentum going.</p>\n\n\n\n<p>Old tickets, because it&#8217;s something that we hope for year after year when we&#8217;re talking to people about what they want in new releases. So often, part of what they say is some way to work through all of these old things that have been around forever, some with patches. And why not, after all?</p>\n\n\n\n<p>And then new meetups, because I really still think that meetups are the best intro to WordPress. No matter whether you&#8217;re wanting to become a developer eventually or, like, the community-building aspect is the thing that hooks you forever. Meetups are the place to encourage those and discover those.&nbsp;</p>\n\n\n\n<p>[00:03:20] <strong>Josepha:</strong> The next thing on my list is also two things. It&#8217;s two things, but kind of a guess at the moment. There are two summit items that I want us to try to consider this year.</p>\n\n\n\n<p>So the first one is contributor recognition. Acknowledgment and recognition, I think, are two different things, and there was an entire series of sessions at the summit where we talked about it. And so I think that it&#8217;s worth us digging in on that.</p>\n\n\n\n<p>The other thing from the summit that I would really like us to all kind of dig in on is accessibility, how we do it, how we confirm it, what we think we should do versus what we actually do, and see what we can move on the needle there.</p>\n\n\n\n<p>And the last thing is sort of a personal wish. I think it&#8217;s about time that we take a look at the way that we kind of manage ourselves as a project, the way that we do our meetings and report on our successes, things like that. And I realize that this is a big thing, and it might be a little bit scary. But, I mean, we&#8217;ve been doing this for a really long time, and it&#8217;s probably as good a time as any, frankly, to look at what we&#8217;re doing by habit or tradition and see if it still suits us.</p>\n\n\n\n<p>So, that&#8217;s my back of the napkin set of notes so far. Keep an eye out in the next couple of weeks for the annual Big Picture post so you can get some context, notes, and discussion opportunities. And, of course, anything that has shown up that&#8217;s a bit bigger, a bit more final will be in there as well.&nbsp;</p>\n\n\n\n<p>But first, our small list of big things. </p>\n\n\n\n<p>[00:04:52] (Music interlude)&nbsp;</p>\n\n\n\n<p>[00:05:00] <strong>Josepha:</strong> Firstly, State of the Word had nearly 200 questions submitted, and Matt has been answering the overflow on make.WordPress.org/project. So, I&#8217;ll include a link, but head on over there to that post if you would like to catch up on those.</p>\n\n\n\n<p>And then the second item, and last item, is that you&#8217;ve got a few more days left to give us feedback on WordPress meetups in 2023, and give us an idea of what we can do to improve those. I believe those close on January 14th. I really love my local meetup, and I hope that we can get some of that same sort of feeling going in all of yours, too.</p>\n\n\n\n<p>[00:05:33] <strong>Josepha:</strong> And that, my friends, is your small list of big things. Don&#8217;t forget to follow us on your favorite podcast app or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser, or if you had questions about what you heard, you can share those with me at wpbriefing@WordPress.org.</p>\n\n\n\n<p>I&#8217;m your host, Josepha Haden Chomphosy. Thanks again for tuning in for the WordPress Briefing, and I&#8217;ll see you again in a couple of weeks.&nbsp;</p>\n\n\n\n<p>[00:06:02] (Music outro)&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16677\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"The Month in WordPress – December 2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://wordpress.org/news/2024/01/the-month-in-wordpress-december-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 05 Jan 2024 10:10:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:18:\"Month in WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:18:\"month in wordpress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16680\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:331:\"As 2023 came to a close, WordPress bid farewell with the much-anticipated annual State of the Word and the 6.5 roadmap, among other exciting updates. Read on to learn more about the community’s end-of-year celebrations and catch a sneak peek of what’s in store for the year ahead. Highlights from State of the Word On [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Reyes Martínez\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11236:\"\n<p>As 2023 came to a close, WordPress bid farewell with the much-anticipated annual State of the Word and the 6.5 roadmap, among other exciting updates.</p>\n\n\n\n<p>Read on to learn more about the community’s end-of-year celebrations and catch a sneak peek of what’s in store for the year ahead.</p>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Highlights from State of the Word</h2>\n\n\n\n<p>On December 11, WordPress co-founder Matt Mullenweg delivered his annual <strong><a href=\"https://wordpress.org/state-of-the-word/\">State of the Word</a> keynote in Madrid, Spain</strong>, marking the first international edition of the event. Nearly 200 WordPress enthusiasts and tech industry leaders gathered in person to hear what’s next for WordPress—with a large audience joining online or from one of the 47 watch parties held across 18 countries.</p>\n\n\n\n<p>The keynote <a href=\"https://wordpress.org/news/2023/12/state-of-the-word-2023-recap/\">highlighted</a> last year’s milestones and showcased compelling demos, providing a glimpse into the upcoming developments for the Site Editor, Collaboration phase, and Admin redesign. Matt also introduced 2024’s focus on <a href=\"https://wordpress.org/data-liberation/\">Data Liberation</a>, aiming to unlock digital barriers and frictionless migrations into WordPress for a more open web.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/c7M4mBVgP3Y?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<p>The event concluded with a <a href=\"https://www.youtube.com/watch?v=S01uBD2pyQY\">Q&amp;A session</a> and <a href=\"https://make.wordpress.org/project/2023/12/12/overflow-questions-from-state-of-the-word-2023/\">this follow-up post</a>.</p>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Roadmap to WordPress 6.5</h2>\n\n\n\n<p>WordPress 6.5 is <a href=\"https://make.wordpress.org/core/6-5/\">scheduled</a> for release on <strong>March 26, 2024</strong>. This major release is set to introduce a new Font Library for easy global font management, support for Appearance Tools in Classic Themes, Data Views for templates and patterns, and more robust revisions across the editing experience, among other highlights.</p>\n\n\n\n<p>6.5 will also include new APIs like Interactivity, Custom Fields, and Block Binding that expand block capabilities and underpin features like Synced Pattern Overrides.</p>\n\n\n\n<p>Learn more about the features planned for WordPress 6.5 in <a href=\"https://make.wordpress.org/core/2023/12/07/roadmap-to-6-5/\">this roadmap post</a>.</p>\n\n\n\n<blockquote class=\"wp-block-quote has-extra-large-font-size\">\n<p>Don’t wait for the next release to optimize your creative workflows with <a href=\"https://wordpress.org/news/2023/12/leap-into-2024-with-these-site-editor-tools/\">these powerful Site Editor tools</a>.</p>\n</blockquote>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">New in the Gutenberg plugin</h2>\n\n\n\n<p>Two new versions of Gutenberg shipped in December:</p>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/12/06/whats-new-in-gutenberg-17-2-6-december/\"><strong>Gutenberg 17.2</strong></a> introduced improvements to the site editing experience, including the ability to drag and drop blocks to the top and bottom of documents and sticky table headers. The update also enhanced the Interactivity API docs and addressed numerous bug fixes.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/12/20/whats-new-in-gutenberg-17-3-20-december/\"><strong>Gutenberg 17.3</strong></a> featured a summary of changes in the global styles revision history, an updated preferences panel, and a new social icon for the Gravatar service, along with the ongoing development of Phase 3 features.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<a class=\"wp-block-jetpack-podcast-player jetpack-podcast-player__direct-link\" href=\"https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/\">https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/</a>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Team updates</h2>\n\n\n\n<ul>\n<li>Openverse <a href=\"https://make.wordpress.org/openverse/2023/12/11/introducing-enhanced-content-safety-features-on-openverse/\">introduced new features to filter sensitive content</a>, aiming for a more accessible and safer browsing experience. This update marks the beginning of a significant initiative to enhance content safety tools.</li>\n\n\n\n<li>Matrix contributors <a href=\"https://make.wordpress.org/project/2023/12/12/update-on-matrix-migration-pausing-the-transition/\">announced</a> the decision to pause the Making WordPress Slack migration to Matrix and the factors contributing to it.</li>\n\n\n\n<li>The <a href=\"https://make.wordpress.org/meta/2023/12/15/developer-resources-gets-a-refresh/\">redesign of the Developer Resources section</a> went live last month.</li>\n\n\n\n<li>Are you searching for events in your local community? Explore the recently launched <a href=\"https://make.wordpress.org/community/2023/12/13/announcing-the-new-wordpress-events-page/\">WordPress.org Events page</a>—your new central hub for discovering upcoming events or applying to organize one.</li>\n\n\n\n<li>In 2023, WordPress significantly <a href=\"https://make.wordpress.org/core/2023/12/19/wordpress-performance-impact-on-core-web-vitals-in-2023/\">improved Core Web Vitals (CWV) across sites</a>. The overall passing rates went up from 28.31% to 36.44% on mobile and from 32.55% to 40.80% on desktop, making both WordPress and the whole web perform better.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/12/22/call-to-action-2024-major-releases-call-for-volunteers/\">Volunteers are needed</a> for 2024’s WordPress major releases. If you’re interested, now’s the time to get involved!</li>\n\n\n\n<li>Check out all the community <a href=\"https://make.wordpress.org/project/2023/12/22/wordpress-end-of-year-celebrations/\">achievements and contributions</a> that moved the WordPress project closer to its goals in 2023.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<a class=\"wp-block-jetpack-podcast-player jetpack-podcast-player__direct-link\" href=\"https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/\">https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/</a>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Requests for feedback &amp; testing</h2>\n\n\n\n<ul>\n<li>Complete the <a href=\"https://make.wordpress.org/community/2023/11/17/announcing-the-2023-annual-meetup-survey/\">2023 Annual Meetup Survey</a> before January 14, 2024, and help strengthen WordPress meetups in the future.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress events</h2>\n\n\n\n<ul>\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1f9-1f1fc.png\" alt=\"🇹🇼\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> WordCamp Asia has opened <a href=\"https://asia.wordcamp.org/2024/contributor-day-registration/\">registrations for its Contributor Day</a>. The conference will be held in Taipei, Taiwan, on March 7-9, 2024.</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ea-1f1fa.png\" alt=\"🇪🇺\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> WordCamp Europe’s <a href=\"https://europe.wordcamp.org/2024/speakers/call-for-speakers/\">call for speakers</a> is open until January 15, 2024. Don’t miss the chance to be part of this event by either submitting your speaking proposals or <a href=\"https://europe.wordcamp.org/2024/sponsors/call-for-sponsors/\">supporting it as a sponsor</a>.</li>\n\n\n\n<li>Mark your calendars! <a href=\"https://us.wordcamp.org/2024/\">WordCamp US 2024</a> is headed to Portland, Oregon, from September 17 to 20, as revealed during the State of the Word.</li>\n\n\n\n<li>Check out these WordPress events happening soon:\n<ul>\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ee-1f1f3.png\" alt=\"🇮🇳\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://events.wordpress.org/kolkata/2024/careercamp/\">Kolkata CareerCamp</a>, India on January 6, 2024</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1f3-1f1f5.png\" alt=\"🇳🇵\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://nepal.wordcamp.org/2024/\">WordCamp Nepal</a> on January 12-13, 2024</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ea-1f1f8.png\" alt=\"🇪🇸\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://zaragoza.wordcamp.org/2024/\">WordCamp Zaragoza</a>, Spain on January 19-20, 2024</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ee-1f1e9.png\" alt=\"🇮🇩\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://events.wordpress.org/jakarta/2024/web-challenge/\">WordPress Web Challenge</a>, Indonesia on January 27, 2024</li>\n</ul>\n</li>\n</ul>\n\n\n\n<div style=\"height:1px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p><em><strong>Have a story we should include in the next issue of The Month in WordPress? Fill out </strong></em><a href=\"https://make.wordpress.org/community/month-in-wordpress-submissions/\"><strong><em>this quick form</em></strong></a><em><strong> to let us know.</strong></em></p>\n\n\n\n<p><em>Thank you to <a href=\"https://profiles.wordpress.org/bernard0omnisend/\">Bernard Meyer</a>, <a href=\"https://profiles.wordpress.org/eidolonnight/\">Nicholas Garofalo</a>, and <a href=\"https://profiles.wordpress.org/laurlittle/\">Lauren Stein</a></em> <em>for contributing to this edition of The Month in WordPress.</em></p>\n\n\n\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<h3 class=\"wp-block-heading\">Subscribe to WordPress News</h3>\n\n\n\n<p>Join other subscribers and receive WordPress news directly in your inbox.</p>\n\n\n<div class=\"wp-block-jetpack-subscriptions__supports-newline is-style-split wp-block-jetpack-subscriptions\">\n		<div>\n			<div>\n				<div>\n					<p >\n						<a href=\"https://wordpress.org/news/?post_type=post&#038;p=16680\" style=\"text-decoration: none; font-size: 16px;padding: 15px 23px 15px 23px;margin: 0px; margin-left: 10px;border-radius: 0px;border-width: 1px; background-color: #113AF5; color: #FFFFFF;\">Subscribe</a>\n					</p>\n				</div>\n			</div>\n		</div>\n	</div></div>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16680\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:75:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n\n\n\n\n\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"d