"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:6:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:70:\"https://wordpress.org/news/files/2023/12/Command-Palette-news-post.mp4\";s:6:\"length\";s:7:\"5553759\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:70:\"https://wordpress.org/news/files/2023/12/Style-book-news-post-demo.mp4\";s:6:\"length\";s:8:\"30842905\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:75:\"https://wordpress.org/news/files/2023/12/Styling-options-news-post-demo.mp4\";s:6:\"length\";s:8:\"27873396\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:88:\"https://wordpress.org/news/files/2023/12/Distraction-free-and-preview-news-post-demo.mp4\";s:6:\"length\";s:8:\"24659305\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:68:\"https://wordpress.org/news/files/2023/12/Patterns-news-post-demo.mp4\";s:6:\"length\";s:7:\"3617911\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:69:\"https://wordpress.org/news/files/2023/12/List-View-news-post-demo.mp4\";s:6:\"length\";s:7:\"2163970\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"annezazu\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9352:\"\n<p>The Site Editor gives you a powerful way to visually create every part of your site and tell your story. It lets you handle everything from big stylistic changes to simple copy updates all in a single place. To help you make the most of this new way to WordPress, here are a few standout tools and features you’ll want to try.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\">Command Palette</h3>\n\n\n\n<p>Think of the Command Palette as the ultimate shortcut tool, letting you do more with less clicks and without needing to remember where each option might be. It’s available across the editing experience, whether you’re switching between templates in the Site Editor or toggling open settings in the Post Editor, with specific contextual options depending on where you are.<strong> </strong>You can use the keyboard shortcut Cmd+K on Mac or Ctrl+K on Windows to activate it and get started.&nbsp;</p>\n\n\n\n<p>If you think of a command that doesn’t exist yet that would help with your workflow, open a <a href=\"https://github.com/WordPress/gutenberg/issues/new/choose\">feature request issue</a> so we can consider adding it.</p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/Command-Palette-news-post.mp4\"></video></figure>\n\n\n\n<p class=\"is-style-default\"><a href=\"https://make.wordpress.org/core/2023/09/12/core-editor-improvement-commanding-the-command-palette/\"><em>Read more</em></a><em> about everything you can do with the Command Palette, including a </em><a href=\"https://wordpress.org/documentation/article/site-editor-command-palette/#list-of-available-commands\"><em>list of available commands</em></a><em>.&nbsp;</em></p>\n\n\n\n<h3 class=\"wp-block-heading\">Style Book</h3>\n\n\n\n<p>The Style Book helps you see all the blocks on your site as you style them. It’s built into the Styles section and can be toggled on/off as you’d like. This is especially useful when you’re aiming for design consistency for a client, trying to see how a change might impact a block that might not be visible, or wanting to get a different look at how a style variation will switch things up.</p>\n\n\n\n<p>Work is also underway for the next WordPress release to <a href=\"https://github.com/WordPress/gutenberg/pull/56800\">integrate the Style Book into Style revisions</a> to allow for an at-a-glance view of changes made. </p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/Style-book-news-post-demo.mp4\"></video></figure>\n\n\n\n<p><a href=\"https://learn.wordpress.org/tutorial/how-to-use-the-wordpress-stylebook-with-your-block-theme/\"><em>Learn more</em></a><em> about how best to use the Style Book.</em></p>\n\n\n\n<h3 class=\"wp-block-heading\">Styling shortcuts</h3>\n\n\n\n<p>Sometimes you get a design just right—the color contrast, the perfect padding, the exact font size. Instead of needing to manually recreate the design or copy/paste the block to fill in with new content, you have two powerful options built into the editing experience: copy/paste styles and apply styles globally for all instances of the desired block.&nbsp;</p>\n\n\n\n<p>Copying and pasting styles is perfect for more nuanced and smaller changes, like headings on a landing page that you intentionally want to be distinct. Applying changes globally is best for blocks like buttons and for changes that are likely to work well across layouts, like setting a specific border radius and color. This helps keep the creativity flowing and makes achieving design consistency across your site much easier.</p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/Styling-options-news-post-demo.mp4\"></video></figure>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2023/02/01/core-editor-improvement-strengthening-style-options/\"><em>Read more</em></a><em> about the various styling options available.&nbsp;</em></p>\n\n\n\n<h3 class=\"wp-block-heading\">Distraction free mode</h3>\n\n\n\n<p>Just like an artist might need to take a few steps back to view their in-progress artwork, sometimes we need to get a different view of our site before diving back in. Distraction free offers you that alternate perspective with a pared-down experience that lets you focus purely on creating, like:</p>\n\n\n\n<ul>\n<li>Hiding the top toolbar until one intentionally hovers over where it typically sits.</li>\n\n\n\n<li>Removing many of the top toolbar buttons.</li>\n\n\n\n<li>Automatically closing any open sidebars, like block settings and list view.&nbsp;</li>\n\n\n\n<li>Hiding the insertion point indicator, reducing visual clutter.&nbsp;</li>\n\n\n\n<li>Hiding the block toolbar for individual blocks.</li>\n</ul>\n\n\n\n<p>It’s worth noting that this mode can be used when writing posts and pages too! For an added bonus and more views of your site, you can use the preview options to see how your site might look across different devices.</p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/Distraction-free-and-preview-news-post-demo.mp4\"></video></figure>\n\n\n\n<p><a href=\"https://wordpress.org/documentation/article/distraction-free-mode/\"><em>Learn more</em></a><em> about making the most out of Distraction free mode.&nbsp;</em></p>\n\n\n\n<h3 class=\"wp-block-heading\">Patterns</h3>\n\n\n\n<p>Patterns are a collection of blocks that make it simple to add complex layouts and designs to any WordPress site without starting from scratch. They save time by reducing duplication and ensuring consistency. You can create your own, use theme-provided patterns, or <a href=\"https://wordpress.org/patterns/\">lean on the Pattern Directory</a>.&nbsp;</p>\n\n\n\n<p>You can also specify whether to sync your patterns so that one change applies to all parts of your site, or to keep them unsynced so you can customize each instance. For any patterns you create, you can assign categories to make them easy to find and organize. Use the Inserter with easy filtering options to add patterns to your content, and head to the dedicated Patterns section in the Site Editor to create or edit patterns to your liking.&nbsp;</p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/Patterns-news-post-demo.mp4\"></video></figure>\n\n\n\n<p><a href=\"https://learn.wordpress.org/tutorial/creating-your-own-custom-synced-or-non-synced-patterns/\"><em>Learn more</em></a><em> about creating patterns.&nbsp;</em></p>\n\n\n\n<h3 class=\"wp-block-heading\">List View</h3>\n\n\n\n<p>List View is the go-to tool for navigating between layers of your content, selecting exactly what you need, and getting a sense of how everything fits together. Similar to the Style Book and Distraction free mode, you can toggle it on/off as you’d like. It’s currently visible in the Top Toolbar and will remain open as you navigate through your site. Beyond providing a simple view of the layers of your site, there are more recent additions to List View that makes the tool even more powerful:</p>\n\n\n\n<ul>\n<li>See previews of your images for Image and Gallery blocks reflected in List View to make it easier to find what you need.</li>\n\n\n\n<li>The Escape key deselects blocks to make it easier to purely preview your content without any blocks selected.&nbsp;</li>\n\n\n\n<li>Lean on a keyboard shortcut for duplicating blocks quickly: CMD+Shift+D for Mac or Control + Shift + D for Windows.&nbsp;</li>\n\n\n\n<li>Drag and drop blocks at any level directly within List View.</li>\n\n\n\n<li>Rename Group blocks and have the custom name reflected in List View for improved organization.</li>\n</ul>\n\n\n\n<p>Here’s how a few of these improvements come together:</p>\n\n\n\n<figure class=\"wp-block-video\"><video controls src=\"https://wordpress.org/news/files/2023/12/List-View-news-post-demo.mp4\"></video></figure>\n\n\n\n<p><a href=\"https://wordpress.org/documentation/article/list-view/\"><em>Learn more</em></a><em> about using List View. </em></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p>As you explore these tools, remember that, except for the Style Book, you can use these features when writing posts and pages too. Expect the Site Editor and other tools to evolve with each release. To get a sneak peek at what’s planned for the next major WordPress release in March, <a href=\"https://make.wordpress.org/core/2023/12/07/roadmap-to-6-5/\">check out the roadmap</a> and stay tuned. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Subscribe to WordPress News</h3>\n\n\n\n<p>Join other subscribers and receive WordPress news directly in your inbox. </p>\n\n\n<div class=\"wp-block-jetpack-subscriptions__supports-newline wp-block-jetpack-subscriptions\">\n		<div>\n			<div>\n				<div>\n					<p >\n						<a href=\"https://wordpress.org/news/?post_type=post&#038;p=16658\" style=\"text-decoration: none; font-size: 16px;padding: 15px 23px 15px 23px;margin: 0px; margin-left: 10px;border-radius: 0px;border-width: 1px; background-color: #113AF5; color: #FFFFFF;\">Subscribe</a>\n					</p>\n				</div>\n			</div>\n		</div>\n	</div>\n\n\n<p><em>Thank you to the contributors who collaborated on this post: <a href=\"https://profiles.wordpress.org/eidolonnight/\">Nicholas Garofalo</a>, <a href=\"https://profiles.wordpress.org/laurlittle/\">Lauren Stein</a>, <a href=\"https://profiles.wordpress.org/joen/\" data-type=\"link\" data-id=\"https://profiles.wordpress.org/joen/\">Joen Asmussen</a></em>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16658\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"WP Briefing: Episode 69: Reflections on State of the Word\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://wordpress.org/news/2023/12/episode-69-reflections-on-state-of-the-word/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 26 Dec 2023 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=16654\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:232:\"In this episode, WordPress Executive Director Josepha Haden Chomphosy reflects on the recent 2023 State of the Word, which took place in Madrid, Spain, and some of the highlights of the work across the WordPress open source project.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:51:\"https://wordpress.org/news/files/2023/12/WPB069.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10686:\"\n<p>In this episode, WordPress Executive Director Josepha Haden Chomphosy reflects on the recent 2023 State of the Word, which took place in Madrid, Spain, and some of the highlights of the work across the WordPress open source project.</p>\n\n\n\n<p><em><strong>Have a question you’d like answered? You can submit them to&nbsp;<a href=\"mailto:wpbriefing@wordpress.org\">wpbriefing@WordPress.org</a>, either written or as a voice recording.</strong></em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul>\n<li><a href=\"https://wordpress.org/news/2023/12/state-of-the-word-2023-recap/\">State of the Word Recap</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/project/2023/05/17/wordpress-contributor-mentorship-program-pilot-program-proposal/\">WordPress Contributor Mentorship Program: Pilot Program Proposal</a></li>\n\n\n\n<li><a href=\"https://developer.wordpress.org/news/\">WordPress Developer Blog</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/project/2023/12/22/wordpress-end-of-year-celebrations/\">WordPress End of Year Celebrations!</a></li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul>\n<li><a href=\"https://make.wordpress.org/openverse/2023/12/11/introducing-enhanced-content-safety-features-on-openverse/\" target=\"_blank\" rel=\"noreferrer noopener\">Introducing Enhanced Content Safety Features on Openverse</a>&nbsp;&#8211; Introducing new features for enhanced content safety on Openverse. </li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/\" target=\"_blank\" rel=\"noreferrer noopener\">Alert: WordPress Security Team Impersonation Scams</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/plugins/2023/12/02/join-the-plugin-review-team/\" target=\"_blank\" rel=\"noreferrer noopener\">Join the Plugin Review Team!</a> &#8211; The Plugin Review Team is looking for new members; the deadline to apply is on December 31, 2023.</li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcripts</h2>\n\n\n\n<span id=\"more-16654\"></span>\n\n\n\n<p>[00:00:00] <strong>Josepha:</strong> Hello everyone, and welcome to the WordPress Briefing. The podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I’m your host, Josepha Haden Chomphosy. Here we go.</p>\n\n\n\n<p>[00:00:28] (Intro music)&nbsp;</p>\n\n\n\n<p>[00:00:40]&nbsp;<strong>Josepha:</strong> We wrapped up State of the Word earlier this month, and while I was sitting there being the only person to clap for the love of cake, I realized just how much we have been able to accomplish this year. And on the one hand, I shouldn&#8217;t be surprised.</p>\n\n\n\n<p>After all, progress is radical over time yet incremental in time. But all told, 2023 has been a big year for WordPress. There&#8217;s been some radical progress in a few places. There are the things you know because you&#8217;ve heard them all year. You heard them in State of the Word.</p>\n\n\n\n<p>We turned 20, for instance. We shipped three on-time releases. We had three well-organized flagship events, and we prototyped essential parts of phase 3. But there&#8217;s a lot of work that happens outside of flagship events and software releases, and I&#8217;d like to highlight a few examples of operational excellence in our community and ecosystem.</p>\n\n\n\n<p>[00:01:31] <strong>Josepha:</strong> First highlight goes to the contributors who are building community. Going back to 2021, we&#8217;ve been working to bring people back together in person.</p>\n\n\n\n<p>And in that year, we had 19 events. In 2022, we had 24 events, so a modest increase of just over 30%. But then, in 2023, the WordPress community banded together on a campaign to reignite passion in our Meetup groups and encourage playfulness in our WordCamp planning. And not only did we see a 57% increase in active Meetup groups, But we also saw a 116% increase in WordCamps, 54 WordCamps in all. That&#8217;s about a third of the way to our all-time annual high of 142.</p>\n\n\n\n<p>And to complement these in-person opportunities, Learn also shipped 104 pieces of new content and hosted 258 online workshops because location should never be a barrier to entry for joining WordPress.&nbsp;</p>\n\n\n\n<p>[00:02:32] <strong>Josepha:</strong> Second highlight goes to the contributors who are managing our directories. We do have a lot of directories. We have Plugins, Themes, Photos, Block plugins. We got a lot.</p>\n\n\n\n<p>And I&#8217;m sure that everyone saw the consistent and borderline pleading calls to join the Plugin team this year. And for folks who&#8217;ve been around a bit, you probably recall a similar set of consistent and pleading calls to join the Theme team a few years back. Concurrent with the work to refill that contribution pipeline, folks over in Meta and across the project generally, were working on automating as many checks as possible, loosening guidelines where it was reasonable, and modernizing as many processes as we could.</p>\n\n\n\n<p>I&#8217;m happy to share that the theme wait time is at a historic low, with their longest wait sometimes just at a week. And as anxious as I am about the plugin wait times, we&#8217;re actually seeing a lot of progress there as well. As we follow a process similar to the one that we did on themes, I imagine it&#8217;s only gonna get better. So, in 2023, we&#8217;ve onboarded six new team members. And since September, the number of plugins awaiting initial review has been cut in half.</p>\n\n\n\n<p>And then coming up in Q1 of 2024, we&#8217;ll have a project focused entirely on automating as many checks as possible. So I still need you, but I also need you to know that your work there matters and is having an impact.</p>\n\n\n\n<p>[00:03:55] <strong>Josepha:</strong> The third highlight goes to the contributors who are doing outreach. This year, we launched a mentorship program with an 89% completion rate because we&#8217;ve seen time and again that our most prolific contributors had someone at the start that they felt safe asking dumb questions with. We launched and nurtured the developer blog, which was a need identified by the community because there was no place for intermediate and advanced developers to get excited about their cool explorations. And there were 53 posts there this year with thirteen thousand views, which is a 251% increase for the record, which is a ridiculous increase, but it&#8217;s a lot. Thirteen thousand views is a lot.</p>\n\n\n\n<p>We have focused on documentation as we suggested in Porto of 2022. And marketing, I know not always our favorite topic, but marketing, our ability to talk about ourselves to more than just ourselves, has increased dramatically this year.&nbsp;</p>\n\n\n\n<p>Not only have we started rolling out a modern design across our website, but we also are present and engaged on eight different platforms with 20-plus episodes of this very podcast and also video content that netted us seven and a half million views this year. That&#8217;s a lot of numbers, and there&#8217;s a post that goes with it.</p>\n\n\n\n<p>[00:05:10] <strong>Josepha:</strong> Check out the show notes. But if you&#8217;re not gonna check out the show notes because you listen to this on Pocket Casts or Google or something, go to make.WordPress.org/project, and it&#8217;ll be over there. But the point is, it&#8217;s been a banner year for the software, and I am grateful for every tester, designer, and developer that showed up for it. But I also know that what makes WordPress truly irreplaceable is our ecosystem, and it&#8217;s contributions like this and the contributors who do them that make our ecosystem vibrant and responsive and thriving on into the future.</p>\n\n\n\n<p>So, thank you all for the contributions you make to WordPress. Thank you for the shining example of how to do open source at scale, and thank you for another great year together.&nbsp;</p>\n\n\n\n<p>[00:06:04] <strong>Josepha:</strong> Which brings us now to our small list of big things. It is indeed a small this time. First up, I would like to introduce our enhanced content safety features on Openverse. By default, search results now exclude openly licensed media containing sensitive textual content. But this new feature adds additional filtering based on titles, tags, and descriptions of the work as well.</p>\n\n\n\n<p>[00:06:27] <strong>Josepha:</strong> The second thing on our small list of big things is that there is just a general alert. There&#8217;s a WordPress security team impersonation scam that&#8217;s going on out there. The team is aware of multiple ongoing phishing scams impersonating both the WordPress team and the WordPress security team in an attempt to convince administrators to install a plugin on their website which contains malware. I&#8217;ll include a link to that post just in case you have anyone that you think might need to be aware of that, but also all of our site administrators know. Like, WordPress is not gonna email you asking for passwords or anything ever. </p>\n\n\n\n<p>[00:07:02] <strong>Josepha:</strong> And item number three, I would like you to join the Plugin review team. I know I just said it in the body of the episode. But, the Plugin review team is looking for new members still who believe in our mission of guiding plugin authors in responsibly transforming their innovative ideas into reality and ensuring a great WordPress plugin experience for end users. There is a deadline to apply; it&#8217;s December 31st. And so you can get that done over the holidays, over a glass of eggnog if that&#8217;s how you choose to celebrate whatever it is that you do. </p>\n\n\n\n<p>And that&#8217;s it for your small list of big things.&nbsp;</p>\n\n\n\n<p>Don&#8217;t forget to follow us on your favorite podcast app or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser. Or, if you had questions about what you heard, you can share those with me at wpbriefing@WordPress.org. I&#8217;m your host, Josepha Haden Chomphosy. See you again in a couple of weeks.&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16654\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"State of the Word 2023 Recap\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://wordpress.org/news/2023/12/state-of-the-word-2023-recap/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 11 Dec 2023 22:55:46 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:17:\"state of the word\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16617\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:384:\"On December 11, WordPress co-founder Matt Mullenweg traveled to beautiful Madrid, Spain, to deliver his annual State of the Word keynote. It was the first time this event took place outside the United States. Against the backdrop of Palacio Neptuno—an iconic architectural gem and UNESCO World Heritage site—nearly 200 contributors, developers, extenders, and friends of [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Nicholas Garofalo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:20461:\"\n<p>On December 11, WordPress co-founder <a href=\"https://profiles.wordpress.org/matt/\">Matt Mullenweg</a> traveled to beautiful Madrid, Spain, to deliver his annual <a href=\"https://wordpress.org/state-of-the-word/\">State of the Word</a> keynote. It was the first time this event took place outside the United States. Against the backdrop of <a href=\"https://www.palacioneptuno.com/\">Palacio Neptuno</a>—an iconic architectural gem and UNESCO World Heritage site—nearly 200 contributors, developers, extenders, and friends of the project came together to hear from Matt, with millions more joining online.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/c7M4mBVgP3Y?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">An introduction from the Executive Director</h2>\n\n\n\n<p>Kicking off the event, <a href=\"https://profiles.wordpress.org/chanthaboune/\" target=\"_blank\" rel=\"noreferrer noopener\">Josepha Haden Chomphosy</a>, Executive Director of the WordPress project, spoke about the community’s heart and spirit as what fuels hope for the future, ensuring the freedoms of the open web for all. She invited Matt on stage with a closing statement of confidence that such values and characteristics will move the project forward into the next 20 years as it has for the last 20.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img fetchpriority=\"high\" decoding=\"async\" width=\"1024\" height=\"682\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_35.jpg?resize=1024%2C682&#038;ssl=1\" alt=\"Josepha Haden Chomphosy, Executive Director of the WordPress project, speaking at a podium \" class=\"wp-image-16627\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_35.jpg?resize=1024%2C682&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_35.jpg?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_35.jpg?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_35.jpg?w=1280&amp;ssl=1 1280w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" data-recalc-dims=\"1\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Looking back at 2023</h2>\n\n\n\n<p>Taking the stage, Matt shared his excitement about the event being the first international State of the Word. He honored the Spanish WordPress community for hosting, citing their past WordCamp accomplishments. From there, Matt jumped right into a reflection of this year’s notable moments. He recalled the project’s 20th-anniversary celebrations, how the software has evolved, and how much more the community came together this year—doubling the number of WordCamps to 70, taking place in 33 countries.</p>\n\n\n\n<div class=\"wp-block-group has-off-white-2-background-color has-background is-layout-flow wp-block-group-is-layout-flow\" style=\"padding-top:var(--wp--preset--spacing--40);padding-right:0;padding-bottom:var(--wp--preset--spacing--40);padding-left:0\">\n<p class=\"has-text-align-center\">We’re always aiming to learn and improve. Tell us how to make meetups better.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-2 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button has-custom-width wp-block-button__width-50\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpressdotorg.survey.fm/2023-meetup-annual-survey?p=1\" target=\"_blank\" rel=\"noreferrer noopener\">Take the 2023 Meetup Survey</a></div>\n</div>\n</div>\n\n\n\n<p>Matt continued with callouts to several resources on <a href=\"https://wordpress.org/\">WordPress.org</a>: the all-new <a href=\"https://events.wordpress.org/\">Events</a> page, the redesigned <a href=\"https://wordpress.org/showcase/\">Showcase</a>, a new <a href=\"https://wordpress.org/remembers/\">WordPress Remembers memorial</a>, and the <a href=\"https://wordpress.org/news/2023/09/openverse-wins-the-2023-oeg-open-infrastructure-award/\">award-winning Openverse</a>. He also demoed <a href=\"https://developer.wordpress.org/playground/\">WordPress Playground</a>, a tool allowing users to experiment with WordPress directly in their browsers, as well as the versatile <a href=\"https://wordpress.org/themes/twentytwentyfour/\">Twenty Twenty-Four default theme</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"682\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_53.jpg?resize=1024%2C682&#038;ssl=1\" alt=\"Matías Ventura, Lead Architect of Gutenberg, speaking on stage at State of the Word\" class=\"wp-image-16621\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_53.jpg?resize=1024%2C682&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_53.jpg?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_53.jpg?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_53.jpg?w=1280&amp;ssl=1 1280w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" data-recalc-dims=\"1\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Collaborative editing and more</h2>\n\n\n\n<p>Matt recapped the four phases of the Gutenberg project, noting that work has begun on Phase 3: Collaboration before passing the microphone to <a href=\"https://profiles.wordpress.org/matveb/\">Matías Ventura</a>, Lead Architect of Gutenberg.&nbsp;</p>\n\n\n\n<p>After a quick interlude in Spanish, Matías acknowledged how much progress had been made on the software this year. He spoke about the aim of the Site Editor to become both an exemplary writing environment and a superior design tool while noting improvements to the&nbsp;<a href=\"https://wordpress.org/documentation/article/footnotes-block/\" target=\"_blank\" rel=\"noreferrer noopener\">Footnotes Block</a>&nbsp;and the ease of&nbsp;<a href=\"https://wordpress.org/documentation/article/distraction-free-mode/\" target=\"_blank\" rel=\"noreferrer noopener\">Distraction Free mode</a>.</p>\n\n\n\n<p>While there was no set timeline for collaboration and workflows, Matías was excited to share a working prototype in the Editor. He showcased some of the most interesting aspects of collaborative editing, including establishing a sync engine that allows real-time edits to be visible across sessions. He invited contributors to test the prototype in the <a href=\"https://wordpress.org/plugins/gutenberg/\">Gutenberg plugin</a> and <a href=\"https://github.com/WordPress/gutenberg/issues/52593\">share their feedback in Github</a>.</p>\n\n\n\n<p>From there, Matías highlighted other exciting developments, including the emphasis on Patterns and their continued evolution as a powerful tool for workflows, and the ability to connect blocks to custom fields. He was thrilled to speak about performance improvements, noting that work is in progress to make the Editor <a href=\"https://www.codevitals.run/project/gutenberg\">at least twice as fast</a>. Speaking about front-end performance, he shared what’s to come with a <a href=\"https://wpmovies.dev/\">demo of the Interactivity API</a>, showcasing how it can make transitions, search, and other interactions instant—all with standard WordPress blocks and features.&nbsp;</p>\n\n\n\n<p>Matías concluded with a look at how the Admin redesign will take cues from the Site Editor, eventually allowing users to shape their WordPress Admin experience based on their unique needs.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"684\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_09.jpg?resize=1024%2C684&#038;ssl=1\" alt=\"WordPress co-founder Matt Mullenweg speaking at a podium\" class=\"wp-image-16624\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_09.jpg?resize=1024%2C684&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_09.jpg?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_09.jpg?resize=768%2C513&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_09.jpg?w=1280&amp;ssl=1 1280w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" data-recalc-dims=\"1\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">AI and Data Liberation</h2>\n\n\n\n<p>Matt returned to the stage to expand on the future of WordPress, reinforcing his past advice to <em>learn AI deeply</em>. He expressed his excitement about what can be accomplished with the wealth of AI tools available, how contributors are already experimenting with natural language processing and WordPress Playground to create and build.</p>\n\n\n\n<p>Finally, Matt introduced an additional focus for the project in 2024: <a href=\"https://wordpress.org/data-liberation/\">Data Liberation</a>, with the goal to make importing from other platforms into WordPress as frictionless as possible. He spoke about the tendency of content management systems to keep users locked in as part of his motivation to <em>unlock digital barriers</em>. The Data Liberation initiative will work on one-click migration and the export format from WordPress.&nbsp;</p>\n\n\n\n<p>More than just tools, Data Liberation reflects the project’s ethos to allow seamless contributions. With that, Matt invited anyone interested to jump into the action, noting a new <a href=\"https://github.com/wordpress/data-liberation\">Data Liberation GitHub repository</a> and forthcoming <a href=\"https://make.wordpress.org/chat/\">Making WordPress Slack</a> channels as places to get started.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Questions and answers</h2>\n\n\n\n<p>Following the presentation, Matt fielded questions from the live-stream and in-person audiences during an interactive question-and-answer session hosted by <a href=\"https://profiles.wordpress.org/monchomad/\">Jose Ramón Padrón (Moncho)</a>.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/S01uBD2pyQY?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<p>Additional questions from the live session will be answered in a follow-up post on <a href=\"https://make.wordpress.org/project\">make.WordPress.org/project</a>. Subscribe to our blog notifications to be sure you don’t miss it. And don’t forget to mark your calendars for next year’s <a href=\"https://asia.wordcamp.org/2024/\">WordCamp Asia</a> (Taipei, Taiwan), <a href=\"https://europe.wordcamp.org/2024/\">WordCamp Europe</a> (Torino, Italy), and WordCamp US (Portland, Oregon, United States).</p>\n\n\n\n<div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-jetpack-tiled-gallery aligncenter is-style-rectangular\"><div class=\"tiled-gallery__gallery\"><div class=\"tiled-gallery__row\"><div class=\"tiled-gallery__col\" style=\"flex-basis:34.98661%\"><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg?strip=info&#038;w=900&#038;ssl=1 900w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg?strip=info&#038;w=1200&#038;ssl=1 1200w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg?strip=info&#038;w=1280&#038;ssl=1 1280w\" alt=\"\" data-height=\"720\" data-id=\"16628\" data-link=\"https://wordpress.org/news/?attachment_id=16628\" data-url=\"https://wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg\" data-width=\"1280\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_37_04-1024x576.jpg?ssl=1\" data-amp-layout=\"responsive\" /></figure><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_22-1024x682.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_22-1024x682.jpg?strip=info&#038;w=900&#038;ssl=1 900w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_22-1024x682.jpg?strip=info&#038;w=1200&#038;ssl=1 1200w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_36_22-1024x682.jpg?strip=info&#038;w=1280&#038;ssl=1 1280w\" alt=\"\" data-height=\"853\" data-id=\"16618\" data-link=\"https://wordpress.org/news/?attachment_id=16618\" data-url=\"http