w-2023-final.006-1024x576.png?strip=info&#038;w=1800&#038;ssl=1 1800w,https://i0.wp.com/wordpress.org/news/files/2023/12/sotw-2023-final.006-1024x576.png?strip=info&#038;w=1920&#038;ssl=1 1920w\" alt=\"\" data-height=\"1080\" data-id=\"16632\" data-link=\"https://wordpress.org/news/?attachment_id=16632\" data-url=\"https://wordpress.org/news/files/2023/12/sotw-2023-final.006-1024x576.png\" data-width=\"1920\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/sotw-2023-final.006-1024x576.png?ssl=1\" data-amp-layout=\"responsive\" /></figure></div><div class=\"tiled-gallery__col\" style=\"flex-basis:24.12657%\"><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_38-576x1024.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_38-576x1024.jpg?strip=info&#038;w=720&#038;ssl=1 720w\" alt=\"\" data-height=\"1280\" data-id=\"16630\" data-link=\"https://wordpress.org/news/?attachment_id=16630\" data-url=\"https://wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_38-576x1024.jpg\" data-width=\"720\" src=\"https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_38-576x1024.jpg?ssl=1\" data-amp-layout=\"responsive\" /></figure></div></div><div class=\"tiled-gallery__row\"><div class=\"tiled-gallery__col\" style=\"flex-basis:63.00314%\"><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i2.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i2.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg?strip=info&#038;w=900&#038;ssl=1 900w,https://i2.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg?strip=info&#038;w=1200&#038;ssl=1 1200w,https://i2.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg?strip=info&#038;w=1280&#038;ssl=1 1280w\" alt=\"\" data-height=\"853\" data-id=\"16620\" data-link=\"https://wordpress.org/news/?attachment_id=16620\" data-url=\"https://wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg\" data-width=\"1280\" src=\"https://i2.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_35_11-1024x682.jpg?ssl=1\" data-amp-layout=\"responsive\" /></figure></div><div class=\"tiled-gallery__col\" style=\"flex-basis:36.99686%\"><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg?strip=info&#038;w=900&#038;ssl=1 900w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg?strip=info&#038;w=1200&#038;ssl=1 1200w,https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg?strip=info&#038;w=1280&#038;ssl=1 1280w\" alt=\"\" data-height=\"720\" data-id=\"16619\" data-link=\"https://wordpress.org/news/?attachment_id=16619\" data-url=\"https://wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg\" data-width=\"1280\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_34_45-1024x576.jpg?ssl=1\" data-amp-layout=\"responsive\" /></figure><figure class=\"tiled-gallery__item\"><img decoding=\"async\" srcset=\"https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg?strip=info&#038;w=600&#038;ssl=1 600w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg?strip=info&#038;w=900&#038;ssl=1 900w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg?strip=info&#038;w=1200&#038;ssl=1 1200w,https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg?strip=info&#038;w=1280&#038;ssl=1 1280w\" alt=\"\" data-height=\"720\" data-id=\"16629\" data-link=\"https://wordpress.org/news/?attachment_id=16629\" data-url=\"https://wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg\" data-width=\"1280\" src=\"https://i1.wp.com/wordpress.org/news/files/2023/12/IMAGE-2023-12-11-13_38_08-1024x576.jpg?ssl=1\" data-amp-layout=\"responsive\" /></figure></div></div></div></div>\n\n\n\n<p><em><em>Thank you to <a href=\'https://profiles.wordpress.org/laurlittle/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>laurlittle</a>, <a href=\'https://profiles.wordpress.org/eidolonnight/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>eidolonnight</a>, <a href=\'https://profiles.wordpress.org/nilovelez/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nilovelez</a>, <a href=\'https://profiles.wordpress.org/fepr/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>fepr</a>, <a href=\'https://profiles.wordpress.org/cbringmann/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>cbringmann</a>, and the many others who made this event and post possible.</em></em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16617\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"WP Briefing: Episode 68: Toward a More Interconnected Web\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://wordpress.org/news/2023/12/episode-68-toward-a-more-interconnected-web/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 11 Dec 2023 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=16569\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:235:\"In this episode, WordPress Executive Director, Josepha Haden Chomphosy articulates the vision for a collaborative ecosystem where knowledge sharing and contributions to open source tools lead to a more interconnected and empowered web.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:51:\"https://wordpress.org/news/files/2023/12/WPB068.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14552:\"\n<p>In this episode, WordPress Executive Director, Josepha Haden Chomphosy articulates the vision for a collaborative ecosystem where knowledge sharing and contributions to open source tools lead to a more interconnected and empowered web.</p>\n\n\n\n<p><em><strong>Have a question you&#8217;d like answered? You can submit them to&nbsp;<a href=\"mailto:wpbriefing@wordpress.org\">wpbriefing@WordPress.org</a>, either written or as a voice recording.</strong></em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul>\n<li><a href=\"https://wordpress.org/news/2022/11/state-of-the-word-2022/\">State of the Word 2022</a></li>\n\n\n\n<li><a href=\"https://thephp.foundation/\">PHP Foundation</a></li>\n\n\n\n<li>Josepha&#8217;s <a href=\"https://make.wordpress.org/project/2022/01/21/big-picture-goals-2022/\">Big Picture Goals 2022</a></li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/11/22/whats-new-in-gutenberg-17-1-22-november/\">Gutenberg 17.1</a> has been released and is <a href=\"https://wordpress.org/plugins/gutenberg/\" target=\"_blank\" rel=\"noreferrer noopener\">available for download</a>! The latest release includes new enhancements, bug fixes, and continued work on Phase 3 features.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2023/11/17/announcing-the-2023-annual-meetup-survey/\" target=\"_blank\" rel=\"noreferrer noopener\">Announcing the 2023 Annual Meetup Survey</a> &#8211; The Community team proposed a survey for all meetup members and organizers. Please complete the <a href=\"https://wordpressdotorg.survey.fm/2023-meetup-annual-survey\" target=\"_blank\" rel=\"noreferrer noopener\">Annual Meetup Survey</a>  by January 14, 2024– even if you haven&#8217;t participated in a meetup recently!</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/training/2023/11/29/request-for-feedback-lesson-handbook-pages/\" target=\"_blank\" rel=\"noreferrer noopener\">Request for feedback: Lesson Handbook pages</a> &#8211; As the Training team progresses towards the 2024 launch of <a href=\"https://make.wordpress.org/training/2023/07/07/project-thread-learning-pathways-on-learn-wordpress/\">Learning Pathways</a>, they&#8217;re developing a set of content creation guidelines to streamline and scale the process. These guidelines will focus on efficient methods for developing, reviewing, and updating content. To gather input, a <a href=\"https://docs.google.com/document/d/1twvDGmVZsyjBZbi9abiqoA_a2G7O_WNis_iGL2Sccg0/edit#heading=h.srkdcrt4k0v8\">Google Doc</a> has been created where you can share your ideas. Please provide your feedback and comments on this document by Tuesday, December 19, 2023.</li>\n\n\n\n<li><a href=\"https://playground.wordpress.net/\">WordPress Playground</a> makes WordPress instantly accessible for users, learners, extenders, and contributors.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/project/2023/11/30/embracing-matrix-for-enhanced-communication/\">Embracing Matrix for Enhanced Communication</a></li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcripts</h2>\n\n\n\n<span id=\"more-16569\"></span>\n\n\n\n<p>[00:00:00] <strong>Josepha:</strong> Hello everyone. And welcome to the WordPress Briefing. The podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I&#8217;m your host, Josepha Haden Chomphosy. Here we go.</p>\n\n\n\n<p>[00:00:28] (Intro music)&nbsp;</p>\n\n\n\n<p>[00:00:40] <strong>Josepha:</strong> If you&#8217;re already familiar with the WordPress project, and if you&#8217;re listening to this podcast, I feel like it&#8217;s a safe assumption that you&#8217;re probably also familiar with the fact that we are what&#8217;s considered a free and open source software project. We adhere to the four freedoms of open source. We track bugs in the open, and we believe that knowledge sharing can only improve our products. </p>\n\n\n\n<p>But you might not be aware of the other open source projects that are foundational to ours and otherwise are integral to our commitment to the open web. At last year&#8217;s State of the Word, Matt mentioned that one of the coolest things about being a plugin or theme author in WordPress is that you get to run your open source project on the same infrastructure that WordPress runs on. So, no matter whether you have five installs or five thousand, you&#8217;re getting the benefits of our bug trackers, messaging, and network of project sites. But beyond those, which are, of course, near and dear to us, we also support projects like PHP and its foundation. Openverse and its founding organization Creative Commons, and of course, the two that we&#8217;re hearing a lot about this year and next, Playground and Matrix.</p>\n\n\n\n<p>[00:01:52] <strong>Josepha:</strong> That&#8217;s a lot of projects and not even a comprehensive list. And honestly, it can seem, I don&#8217;t know, a little weird. Like, we&#8217;re a FOSS CMS, right? You probably know why we contribute back to PHP. It&#8217;s the same reason we ask people to contribute to WordPress. But why are we giving so much time to a media search engine, or a Web Assembly implementation, or even a messaging protocol?</p>\n\n\n\n<p>At first glance, there are, of course, a lot of quick and easy answers. For instance, like, open source is open source. Any open source contribution is going to be a good contribution. All open source in the world increases good and freedom in the world. Like, open source is open source. Makes sense, right?</p>\n\n\n\n<p>Another quick and easy answer is, you know, they&#8217;re part of us. And that&#8217;s true, definitely, for PHP, like, they&#8217;re part of us, and so we should be contributing back to them. Because we rely on them so much. And then a third quick and easy answer is that we, as the biggest open source CMS on the planet, basically, we can, spare a lending hand. We can offer a little bit of help to those around us.&nbsp;</p>\n\n\n\n<p>[00:03:03] <strong>Josepha:</strong> And those are all true. I don&#8217;t think that anyone would disagree with any of that. But the thing that ties it all together for me is something that&#8217;s a little harder to see. In the 2022 goals that I posted, I said that my second goal for our year was to support open source alternatives for all site-building necessities.</p>\n\n\n\n<p>At the time, I was primarily talking about Openverse and the directory of photos that was being created as a CC-first source. But that also applies to all of our directories. It did then, just as it does now. And Trac, and our vast network of WordPress sites. All the tools we use in order to collaborate with, and lead for, and learn from each other.</p>\n\n\n\n<p>I want us to be able to do everything it takes to build an online presence using open source tools and methods because WordPress is just a glorious little microcosm of the interconnected web. It reminds me of this art installation I had the privilege of experiencing. It&#8217;s called Meow Wolf. I went to the one in Denver, but there are a few different installations across the U.S.&nbsp;The one that I went to is this massive art installation, and it is designed to be interactive, but it wasn&#8217;t until you started sharing your experience sharing your knowledge with other people that you realized it was also collaborative, a set of buttons you pushed in one room would cause a light show in some other room.</p>\n\n\n\n<p>[00:04:34] <strong>Josepha:</strong> So you were enhancing the experience of strangers in some completely disconnected room to yours, and they couldn&#8217;t distinguish it from an automation or something they did, or just plain old magic. And that&#8217;s what we&#8217;re doing by supporting these other open source tools. Yes, every new open source contribution results in more freedom in the world. Yes, we owe support to the components that got us where we are today. And yes, we absolutely can and should pay it forward. But more importantly than all that, we&#8217;re creating the opportunity for new interactions, new brilliance, and new defenders of the open web every time that we work on these open source products.</p>\n\n\n\n<p>[00:05:20] <strong>Josepha:</strong> And it doesn&#8217;t matter if we will ever see any of those people. And it doesn&#8217;t matter if they will ever thank us. What matters is that we see that knowledge like this is worth preserving and worth sharing. Because knowledge shared, information shared is like light. The more you share it, the more there is.</p>\n\n\n\n<p>And I want you to be able to take that sharing and use it to light the world. I want you to be able to go out and tell people how open source has changed your life, how WordPress has opened doors for you, or how much these tools have empowered your clients. I want you to remember why you came to WordPress in the first place, and I need you to hear me when I say that I need you here in WordPress today because every little ripple of good that we create makes the world a little more good.</p>\n\n\n\n<p>[00:06:12] (Music interlude)&nbsp;</p>\n\n\n\n<p>[00:06:20] <strong>Josepha:</strong> (SLBT) And now, my friends, that brings us to our time for the small list of big things. I&#8217;ve got a kind of a big list because I always kind of have a big list anymore, but the first thing on my list is Gutenberg 17.1. That has been released and is available for download. It includes several new enhancements, loads of bug fixes, and continues that work on phase three features that we are starting to see come through. If you don&#8217;t have it already, go out and grab it, test it, break it, and tell us what you tested and how it broke things.&nbsp;</p>\n\n\n\n<p>[00:06:52] <strong>Josepha:</strong> The second thing on my small list of big things is that there is currently an annual meetup survey out. So, we&#8217;ve had an increase in our meetup events, and certainly an increase in the active number of meetup groups that we have, but the community team is proposing a unified survey for all meetup members and organizers, and if you haven&#8217;t participated in it yet go and fill it out. You don&#8217;t have to have actually gone to a meetup event recently in order to take it, but, you know, it might be helpful. Either way, you have until January 14, 2024, to fill that out.</p>\n\n\n\n<p>[00:07:30] <strong>Josepha:</strong> The third thing on my small list of big things is a request for feedback. The training team is working toward launching Learning Pathways in 2024. They&#8217;re looking to create a new set of content creation guidelines that enables the learning pathways to scale with a straightforward process for developing, reviewing, and updating that content. There&#8217;s a Google doc for you where you can contribute your ideas, and that doc will be open for feedback through this week and into next week. I believe it closes on Tuesday, the 19th of December, 2023.</p>\n\n\n\n<p>[00:08:04] <strong>Josepha:</strong> And then the final thing on my small list of big things is actually, it&#8217;s a dual call-in. I already said with my first one about the Gutenberg plugin: get in there and test it and break it, and then tell us how it broke and what you were doing when you were testing it and broke it. And I encourage you to do that also for Matrix and Playground.</p>\n\n\n\n<p>So Playground has been a really big deal all year long. It was a big deal at the end of last year. It showed up for us in November 2022 and has been really just growing in surprising ways all the way through 2023. So if you have not yet seen it, you haven&#8217;t gotten your hands on it yet, it&#8217;s a WordPress installation that is loaded entirely in the browser, totally server-free, and we&#8217;re looking at a couple of new implementations that make it easier for users who are trying to, like, kick the tires of WordPress before they decide, and developers who are wanting to test new pull requests and things like that.</p>\n\n\n\n<p>So keep an eye out if it sounds interesting; it is interesting. And wander over and figure out how that&#8217;s working. And the other thing in that last call for collective testing is Matrix. So Matrix is an open source federated messaging protocol, and like so many technology projects out there at the moment, we are trying to make sure that we are preparing ourselves for the future arrival of Web 3 and all of the things that are coming along with current advancements in federated everything and AI and etc., etc.</p>\n\n\n\n<p>And so, Matrix is an open source messaging protocol. There are a lot of different ways to get connected. I&#8217;ll share a link to one of the posts in the show notes over on WordPress.org/news. But if you&#8217;re interested in learning a bit about it and you don&#8217;t really want to like figure out what sort of client is comfortable for you to use. There&#8217;s also on-site chat implementations for, I want to say, like 10 or 12 of our largest or most regularly meeting groups that we have. You can go to parts of the website like make.WordPress.org/core/chat and check those out. If you have a WordPress.org account, then you can have access to that on-site chat, and that is it.</p>\n\n\n\n<p>That&#8217;s the whole low barrier to entryway of figuring that out with us. Come and break stuff with us, everyone, and tell us how to make it better.&nbsp;</p>\n\n\n\n<p>[00:10:33] <strong>Josepha:</strong> And that, my friends, is your small list of big things. Don&#8217;t forget to follow us on your favorite podcast app or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser. Or, if you had questions about what you heard, you can share those with me at wpbriefing@WordPress.org. I&#8217;m your host, Josepha Haden Chomphosy. Thank you for tuning in today for the WordPress Briefing, and I&#8217;ll see you again in a couple of weeks.</p>\n\n\n\n<p>[00:11:00] (Music outro)&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16569\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"The Month in WordPress – November 2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://wordpress.org/news/2023/12/the-month-in-wordpress-november-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 08 Dec 2023 11:20:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:18:\"Month in WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:18:\"month in wordpress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16575\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:251:\"November is usually a busy month for the WordPress project, and this year is no different. Following the empowering release of WordPress 6.4, the energy continues to build, setting the stage for the anticipated State of the Word and upcoming projects.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Reyes Martínez\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11827:\"\n<p>November is usually a busy month for the WordPress project, and this year is no different. Following the empowering release of WordPress 6.4, the energy continues to build, setting the stage for the anticipated State of the Word and upcoming projects.&nbsp;</p>\n\n\n\n<p>Read on for all the exciting updates that marked the past month.</p>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Get ready for State of the Word</h2>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=1024%2C683&#038;ssl=1\" alt=\"State of the Word 2023\" class=\"wp-image-16438\" style=\"object-fit:cover\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=1024%2C683&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=1536%2C1024&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2023/11/SOTW-Blue.png?resize=2048%2C1365&amp;ssl=1 2048w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" data-recalc-dims=\"1\" /></figure>\n\n\n\n<p>Mark your calendars—State of the Word 2023 is approaching fast. In this annual keynote, WordPress co-founder Matt Mullenweg celebrates the progress of the open source project and offers a glimpse into its future.</p>\n\n\n\n<p>For the first time in WordPress history, the event will be held outside North America, in the vibrant city of <a href=\"https://wordpress.org/news/2023/11/state-of-the-word-2023-madrid-spain/\">Madrid, Spain, on December 11, 2023</a>.</p>\n\n\n\n<p>If you’re unable to attend the State of the Word in person, you can watch it live on the <a href=\"https://www.youtube.com/live/1MwT9EEkguE?si=TYwAe5qnKA3DlRMX\">WordPress YouTube channel</a> or join one of the many community-led watch parties. <a href=\"https://wordpress.org/state-of-the-word\">Find one near you</a> or <a href=\"https://make.wordpress.org/community/handbook/meetup-organizer/event-formats/state-of-the-word-watch-parties/\">organize one</a>.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-4 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-dark-strokes-grey-background-color has-text-color has-background has-link-color wp-element-button\" href=\"https://wordpress.org/state-of-the-word/\">Learn more about State of the Word 2023</a></div>\n</div>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Meet Twenty Twenty-Four</h2>\n\n\n\n<p>Along with the release of <a href=\"https://wordpress.org/download/releases/6-4/\">WordPress 6.4</a> “Shirley,” the new default <a href=\"https://wordpress.org/news/2023/11/introducing-twenty-twenty-four/\">Twenty Twenty-Four theme was introduced</a>.</p>\n\n\n\n<p>This theme breaks away from the tradition of previous default themes that focused on a specific topic or style. Instead, Twenty Twenty-Four was created to fit any website and explore different use cases for entrepreneurs, artists, and writers.</p>\n\n\n\n<p>You’ll find more than 35 beautiful patterns, including full-page patterns for templates like homepage, search, and more. Twenty Twenty-Four boasts the latest site editing capabilities and a sophisticated aesthetic inspired by contemporary design trends.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-5 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-dark-strokes-grey-background-color has-text-color has-background has-link-color wp-element-button\" href=\"https://playground.wordpress.net/?theme=twentytwentyfour\">Check out Twenty Twenty-Four now</a></div>\n</div>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">New in the Gutenberg plugin</h2>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/core/2023/11/10/whats-new-in-gutenberg-17-0-9-november/\">Gutenberg 17.0</a> was released on November 9, 2023. It introduced improvements to the Command Palette, an alternative implementation of the DropdownMenu component, additional visual cues for LinkControl, and various accessibility and performance iterations.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/11/22/whats-new-in-gutenberg-17-1-22-november/\">Gutenberg 17.1</a> shipped on November 22, 2023. In addition to several accessibility and writing flow enhancements, this version brought a new block spacing control in the Quote block.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<a class=\"wp-block-jetpack-podcast-player jetpack-podcast-player__direct-link\" href=\"https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/\">https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/</a>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Team updates</h2>\n\n\n\n<ul>\n<li><a href=\"https://make.wordpress.org/project/2023/11/30/embracing-matrix-for-enhanced-communication/\">WordPress is switching to Matrix</a> in replacement of the Making WordPress Slack. The move stems from the project&#8217;s commitment to implementing a new chat system aligned with WordPress&#8217;s open source values. If you haven&#8217;t already, now is the time to explore Matrix and share your questions.</li>\n\n\n\n<li>With phishing scams on the rise, the WordPress Security team is actively monitoring the current threat and has posted <a href=\"https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/\">an advisory to help you protect your site</a>.</li>\n\n\n\n<li>The Plugin Review team is now <a href=\"https://make.wordpress.org/plugins/2023/12/02/join-the-plugin-review-team/\">reopening applications to join their team</a>. They’re looking for three new members who can improve the state of the plugin review queue and help create a diverse and inclusive team.</li>\n\n\n\n<li>Over the past few months, contributors have been working on <a href=\"https://make.wordpress.org/meta/2023/11/22/redesigning-developer-resources-and-a-call-for-testing/\">redesigning the WordPress.org Developer Resources</a> section.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2023/11/06/proposal-2024-major-release-timing/\">This post</a> outlines proposed dates for major WordPress releases in 2024.</li>\n\n\n\n<li>The Meta team shared an <a href=\"https://make.wordpress.org/meta/2023/11/22/plugin-directory-preview-button-revisited/\">improved version of the plugin preview feature</a>. This version builds on feedback and allows plugin developers to safely test the preview experience for their plugins in a <a href=\"https://developer.wordpress.org/playground/\">WordPress Playground</a> environment.</li>\n\n\n\n<li>Polyglots and Meta contributors introduced <a href=\"https://make.wordpress.org/meta/2023/11/29/create-tours-for-make-p2s/\">a new plugin called Tour</a>, which enables the creation of tours to guide contributors through a Make WordPress blog.</li>\n\n\n\n<li>Are you looking to broaden your knowledge and improve your WordPress skills? See <a href=\"https://make.wordpress.org/updates/2023/12/01/whats-new-on-learn-wordpress-in-november-2023/\">what’s new on Learn WordPress in November 2023</a>.</li>\n\n\n\n<li>The latest edition of People of WordPress features back-end web developer <a href=\"https://wordpress.org/news/2023/12/people-of-wordpress-artemy-kaydash/\">Artemy Kaydash</a> from Ukraine.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<a class=\"wp-block-jetpack-podcast-player jetpack-podcast-player__direct-link\" href=\"https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/\">https://wordpress.org/news/2023/10/episode-64-patterns-in-wordpress/</a>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">Requests for feedback &amp; testing</h2>\n\n\n\n<ul>\n<li>The Community team announced the <a href=\"https://make.wordpress.org/community/2023/11/17/announcing-the-2023-annual-meetup-survey/\">2023 Annual Meetup Survey</a>. Both event attendees and organizers are encouraged to provide feedback in this 5-minute survey to help strengthen WordPress meetups in the future.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/updates/2023/11/23/mobile-team-update-november-22nd/\">Version 23.7</a> of the WordPress mobile app for iOS and Android is ready for testing.</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress events</h2>\n\n\n\n<ul>\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1f9-1f1fc.png\" alt=\"🇹🇼\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> WordCamp Asia opened the <a href=\"https://asia.wordcamp.org/2024/the-third-batch-of-tickets-on-sale-now/\">third round of ticket sales</a> and announced that <a href=\"https://asia.wordcamp.org/2024/announcing-our-first-speaker-matt-mullenweg/\">their first speaker is WordPress co-founder Matt Mullenweg</a>. The conference will be held in Taipei, Taiwan, on March 7-9, 2024.</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ea-1f1fa.png\" alt=\"🇪🇺\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> WordCamp Europe <a href=\"https://europe.wordcamp.org/2024/call-for-sponsors/\">opened its call for sponsors</a> and <a href=\"https://europe.wordcamp.org/2024/speakers/call-for-speakers/\">speakers</a> for their conference slated to take place in Torino, Italy, on June 13-15, 2024.&nbsp;</li>\n\n\n\n<li>Don’t miss these upcoming WordCamps:\n<ul>\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1ee-1f1f3.png\" alt=\"🇮🇳\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://ahmedabad.wordcamp.org/2023/\">WordCamp Ahmedabad 2023</a>, India on December 9, 2023</li>\n\n\n\n<li><img src=\"https://s.w.org/images/core/emoji/14.0.0/72x72/1f1f5-1f1f0.png\" alt=\"🇵🇰\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://lahore.wordcamp.org/2023/\">WordCamp Lahore 2023</a>, Pakistan on December 9-10, 2023</li>\n</ul>\n</li>\n</ul>\n\n\n\n<div style=\"height:3px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p><em><strong>Have a story we should include in the next issue of The Month in WordPress? Fill out </strong></em><a href=\"https://make.wordpress.org/community/month-in-wordpress-submissions/\"><strong><em>this quick form</em></strong></a><em><strong> to let us know.</strong></em></p>\n\n\n\n<p><em>Thank you to <a href=\"https://profiles.wordpress.org/bernard0omnisend/\">Bernard Meyer</a> for contributing to this edition of The Month in WordPress.</em></p>\n\n\n\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<h3 class=\"wp-block-heading\">Subscribe to WordPress News</h3>\n\n\n\n<p>Join other subscribers and receive WordPress news directly in your inbox.</p>\n\n\n<div class=\"wp-block-jetpack-subscriptions__supports-newline is-style-split wp-block-jetpack-subscriptions\">\n		<div>\n			<div>\n				<div>\n					<p >\n						<a href=\"https://wordpress.org/news/?post_type=post&#038;p=16575\" style=\"text-decoration: none; font-size: 16px;padding: 15px 23px 15px 23px;margin: 0px; margin-left: 10px;border-radius: 0px;border-width: 1px; background-color: #113AF5; color: #FFFFFF;\">Subscribe</a>\n					</p>\n				</div>\n			</div>\n		</div>\n	</div></div>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16575\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"WordPress 6.4.2 Maintenance &amp; Security Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://wordpress.org/news/2023/12/wordpress-6-4-2-maintenance-security-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 06 Dec 2023 17:03:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Security\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16562\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:352:\"WordPress 6.4.2 is now available! This minor release features 7 bug fixes in Core. The fixes include a bug fix for an issue causing stylesheet and theme directories to sometimes return incorrect results. This release also features one security fix. Because this is a security release, it is recommended that you update your sites immediately. [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Aaron Jorbin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6255:\"\n<h2 class=\"wp-block-heading\">WordPress 6.4.2 is now available!</h2>\n\n\n\n<p>This minor release features <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.4.2&amp;groupdesc=1&amp;group=resolution&amp;col=id&amp;col=summary&amp;col=status&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;col=keywords&amp;order=priority\">7 bug fixes</a> in Core. The fixes include a bug fix for an issue causing stylesheet and theme directories to sometimes return incorrect results.</p>\n\n\n\n<p>This release also features one security fix. Because this is a security release, <strong>it is recommended that you update your sites immediately</strong><strong>.</strong></p>\n\n\n\n<p>You can <a href=\"https://wordpress.org/wordpress-6.4.2.zip\">download WordPress 6.4.2 from WordPress.org</a>, or visit your WordPress Dashboard, click “Updates”, and then click “Update Now”. If you have sites that support automatic background updates, the update process will begin automatically.</p>\n\n\n\n<p>WordPress 6.4.2 is a short-cycle release. The next major release will be version 6.5 released in early 2024.</p>\n\n\n\n<p>For more information on this release, please visit the <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-4-2/\">HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Security updates included in this release</h2>\n\n\n\n<p>The security team addressed the following vulnerability in this release.</p>\n\n\n\n<ul>\n<li>A Remote Code Execution vulnerability that is not directly exploitable in core, however the security team feels that there is a potential for high severity when combined with some plugins, especially in multisite installs.</li>\n</ul>\n\n\n\n<p>To help the security team and WordPressers around the world, you are encouraged to <a href=\"https://hackerone.com/wordpress?type=team\">responsibly report vulnerabilities</a>. This allows vulnerabilities to be fixed in future releases.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p>This release was led by <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>.</p>\n\n\n\n<p>WordPress 6.4.2 would not have been possible without the contributions of the following people. Their asynchronous coordination to deliver maintenance and security fixes into a stable release is a testament to the power and capability of the WordPress community.</p>\n\n\n\n<p class=\"is-style-wporg-props-long\"><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>, <a href=\"https://profiles.wordpress.org/atachibana\">Akira Tachibana</a>, <a href=\"https://profiles.wordpress.org/xknown\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/angelasjin\">Angela Jin</a>, <a href=\"https://profiles.wordpress.org/antonvlasenko\">Anton Vlasenko</a>, <a href=\"https://profiles.wordpress.org/barry\">Barry</a>, <a href=\"https://profiles.wordpress.org/Bernhard%20Reiter\">bernhard-reiter</a>, <a href=\"https://profiles.wordpress.org/icaleb\">Caleb Burks</a>, <a href=\"https://profiles.wordpress.org/coreyw\">Corey Worrell</a>, <a href=\"https://profiles.wordpress.org/crstauf\">crstauf</a>, <a href=\"https://profiles.wordpress.org/nerrad\">Darren Ethier (nerrad)</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>, <a href=\"https://profiles.wordpress.org/dd32\">Dion Hulse</a>, <a href=\"https://profiles.wordpress.org/kebbet\">Erik</a>, <a href=\"https://profiles.wordpress.org/gaambo\">Fabian Todt</a>, <a href=\"https://profiles.wordpress.org/flixos90\">Felix Arntz</a>, <a href=\"https://profiles.wordpress.org/priethor\">Héctor Prieto</a>, <a href=\"https://profiles.wordpress.org/ironprogrammer\">ironprogrammer</a>, <a href=\"https://profiles.wordpress.org/isabel_brison\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/jeffpaul\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/luminuu\">Jessica Lyschik</a>, <a href=\"https://profiles.wordpress.org/joemcgill\">Joe McGill</a>, <a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/kharisblank\">Kharis Sulistiyono</a>, <a href=\"https://profiles.wordpress.org/krupalpanchal\">Krupal Panchal</a>, <a href=\"https://profiles.wordpress.org/kdowns\">Kylen Downs</a>, <a href=\"https://profiles.wordpress.org/meta4\">meta4</a>, <a href=\"https://profiles.wordpress.org/mikeschroder\">Mike Schroder</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/partyfrikadelle\">partyfrikadelle</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/NekoJonez\">Pieterjan Deneys</a>, <a href=\"https://profiles.wordpress.org/rawrly\">rawrly</a>, <a href=\"https://profiles.wordpress.org/rebasaurus\">rebasaurus</a>, <a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>, <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>, <a href=\"https://profiles.wordpress.org/vortfu\">vortfu</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p>To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">pick a ticket</a>, and join the conversation in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a>. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/tutorials/faq-for-new-contributors/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p>As a final reminder, The WordPress Security Team will never email you requesting that you install a plugin or theme on your site, and will never ask for an administrator username and password. <a href=\"https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/\">Please stay vigilant against phishing attacks</a>.</p>\n\n\n\n<p><em>Thanks to <a href=\"https://profiles.wordpress.org/angelasjin/\">@angelasjin</a> and <a href=\"https://wordpress.slack.com/team/U02SVSW3U\">@desrosj</a> for proofreading.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16562\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"Alert: WordPress Security Team Impersonation Scams\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 04 Dec 2023 23:13:35 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:8:\"Security\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"Updates\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=16547\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:368:\"The WordPress Security Team is aware of multiple ongoing phishing scams impersonating both the “WordPress team” and the “WordPress Security Team“ in an attempt to convince administrators to install a plugin on their website which contains malware. The WordPress Security Team will never email you requesting that you install a plugin or theme on your [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Peter Wilson\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4939:\"\n<p>The WordPress Security Team is aware of multiple ongoing phishing scams impersonating both the “WordPress team” and the “WordPress Security Team“ in an attempt to convince administrators to install a plugin on their website which contains malware.</p>\n\n\n\n<p><strong>The WordPress Security Team will never email you requesting that you install a plugin or theme on your site, and will never ask for an administrator username and password.</strong></p>\n\n\n\n<p>If you receive an unsolicited email claiming to be from WordPress with instructions similar to those described above, please disregard the emails and indicate that the email is a scam to your email provider.</p>\n\n\n\n<p>These emails link to a phishing site that appears to be the WordPress plugin repository on a domain that is not owned by WordPress or an associated entity. Both <a href=\"https://patchstack.com/articles/fake-cve-phishing-campaign-tricks-wordpress-users-to-install-malware/\">Patchstack</a> and <a href=\"https://www.wordfence.com/blog/2023/12/psa-fake-cve-2023-45124-phishing-scam-tricks-users-into-installing-backdoor-plugin/\">Wordfence</a> have written articles that go in to further detail.</p>\n\n\n\n<p>Official emails from the WordPress project will always:</p>\n\n\n\n<ul>\n<li>Come from a <code>@wordpress.org</code> or <code>@wordpress.net</code> domain.</li>\n\n\n\n<li>Should also say “Signed by: wordpress.org” in the email details section.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"450\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/12/email-details-signed-by-wordpressdotorg.png?resize=1024%2C450&#038;ssl=1\" alt=\"Screenshot of email sent by a WordPress.org email account. The details include &quot;mailed-by wordpress.org&quot; and &quot;signed-by wordpress.org&quot;.\" class=\"wp-image-16548\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2023/12/email-details-signed-by-wordpressdotorg.png?resize=1024%2C450&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2023/12/email-details-signed-by-wordpressdotorg.png?resize=300%2C132&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2023/12/email-details-signed-by-wordpressdotorg.png?resize=768%2C337&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2023/12/email-details-signed-by-wordpressdotorg.png?w=1202&amp;ssl=1 1202w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" data-recalc-dims=\"1\" /></figure>\n\n\n\n<p>The WordPress Security Team will only communicate with WordPress users in the following locations:</p>\n\n\n\n<ul>\n<li>the Making WordPress Secure blog at <a href=\"https://make.wordpress.org/security\">make.wordpress.org/security</a></li>\n\n\n\n<li>the main WordPress News site at <a href=\"https://wordpress.org/news\">wordpress.org/news</a></li>\n</ul>\n\n\n\n<p>The WordPress Plugin team will never communicate directly with a plugin’s users but may email plugin support staff, owners and contributors. These emails will be sent from <a href=\"mailto:plugins@wordpress.org\">plugins@wordpress.org</a> and be signed as indicated above.</p>\n\n\n\n<p>The official WordPress plugin repository is located at <a href=\"https://wordpress.org/plugins\">wordpress.org/plugins</a> with internationalized versions on subdomains, such as <a href=\"https://fr.wordpress.org/plugins\">fr.wordpress.org/plugins</a>, <a href=\"https://en-au.wordpress.org/plugins\">en-au.wordpress.org/plugins</a>, etc. A subdomain may contain a hyphen, however a dot will always appear before wordpress.org.</p>\n\n\n\n<p>A WordPress site’s administrators can also access the plugin repository via the plugins menu in the WordPress dashboard.</p>\n\n\n\n<p>As WordPress is the most used CMS, these types of phishing scams will happen occasionally. Please be vigilant for unexpected emails asking you to install a theme, plugin or linking to a login form.</p>\n\n\n\n<p>The Scamwatch website has some tips for <a href=\"https://www.scamwatch.gov.au/protect-yourself/ways-to-spot-and-avoid-scams\">identifying emails and text messages that are likely to be scams</a>.</p>\n\n\n\n<p>As always, if you believe that you have discovered a security vulnerability in WordPress, please <a href=\"https://wordpress.org/about/security/\">follow the project’s Security policies</a> by privately and responsibly disclosing the issue directly to the WordPress Security team through the project’s official <a href=\"https://hackerone.com/wordpress\">HackerOne page</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p><em>Thank you <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/otto/\">Otto</a>, <a href=\"https://profiles.wordpress.org/dd32/\">Dion Hulse</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a>, and <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a> for their collaboration on and review of this post.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"16547\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:32:\"https://wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"14607090\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:12:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Tue, 16 Jan 2024 10:24:38 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:25:\"strict-transport-security\";s:12:\"max-age=3600\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Fri, 12 Jan 2024 16:58:53 GMT\";s:4:\"link\";s:63:\"<https://wordpress.org/news/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-fr