xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:5:\"punbb\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:9:\"vbulletin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"http://hu.wordpress.org/?p=25\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:455:\"Ahogyan tapasztalhattátok az elmúlt pár órában a fórum elérhetetlen volt. De most már minden szebb és jobb, mint előtte. A továbbiakban váltás okairól szeretnék egy kicsit mesélni, azoknak, akiket érdekel. Amikor elkezdtünk komolyabban csapattá szerveződni, mi akik moderátorok és adminok vagyunk, valamint a Magyar WordPress Projectben részt veszünk, elköteleztük magunkat a WordPress terjeszetésében, a kapcsolódó [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"DjZoNe\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2330:\"<p>Ahogyan tapasztalhattátok az elmúlt pár órában a fórum elérhetetlen volt.<br />\nDe most már minden szebb és jobb, mint előtte.</p>\n<p>A továbbiakban váltás okairól szeretnék egy kicsit mesélni, azoknak, akiket érdekel.<br />\n<span id=\"more-25\"></span></p>\n<p>Amikor elkezdtünk komolyabban csapattá szerveződni, mi akik moderátorok és adminok vagyunk, valamint a Magyar WordPress Projectben részt veszünk, elköteleztük magunkat a WordPress terjeszetésében, a kapcsolódó technológiák támogatásában, és a felhasználók segítésében.</p>\n<p>Az utóbbiban támadtak nehézségeink az utóbbi időben, ugyanis mióta egyre népszerűbb ez a cms rendszer/blog motor/publikációs platform felbukkantak nem kívánatos elemek, akik örömüket lelték abban, hogy vandálkodni jártak a fórumunka. (trollok)</p>\n<p>Ekkor ébredtünk rá, hogy az eddig használt <strong>PunBB</strong> rendszer nagy hiányosságaiba ütköztünk, és számunkra már nem alkalmas további használatra.</p>\n<p>Gondolkodtunk alternatívákon, hogy mivel lehetne az adatok megtartása mellett leváltani.</p>\n<p>Szempont voltak:</p>\n<ul>\n<li> könnyű kezelhetőség</li>\n<li>moderációs lehetőségek</li>\n<li>kereső barát URL támogatás</li>\n<li>migráló eszközök</li>\n<li>webkettes szolgáltatások támogatása</li>\n</ul>\n<p>Ezek alapján sajnos a <strong>bbPress</strong>-t ki kellett ejtenünk a sorból. Mivel, bár a WordPress kis testvére, és egy nagyon jó fórum rendszer, sajnos a céljainknak ez sem felet meg (ezzel nem zárom ki a lehetőséget, hogy ez a jövőben sem lesz így, viszont még kell neki pár év mire igazán beérik).</p>\n<p>Gyakorlatilag két alternatívánk maradt a <strong>vBulletin</strong> és az <strong>IPB</strong>, és mint láthatjátok ez utóbbi mellett döntöttünk.<br />\nMindenben messze-messze megfelelt az elvárásainknak, sőt egészen sok extrát is tartogatott számunkra.<br />\nAz, hogy az ára is kedvezőbb volt, már csak kellemes ráadás.</p>\n<p>Szóval, meghalt a király(??), éljen a király.<br />\nHasználjátok egészséggel az <a href=\"http://forum.word-press.hu\" target=\"_blank\">új fórum</a>ot.</p>\n<p>Zárszóként pedig, ezúton szeretnénk megköszönni a fordítást az <a href=\"http://ipboard.hu/\">IPB Magyarország</a>nak.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://hu.wordpress.org/2009/09/08/a-kiraly-uj-ruhaja-megujult-a-forumunk/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Egy kis macera\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"https://hu.wordpress.org/2009/08/17/egy-kis-macera/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://hu.wordpress.org/2009/08/17/egy-kis-macera/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 17 Aug 2009 12:21:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:8:\"Gépház\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"weblap\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"http://hu.wordpress.org/?p=23\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:154:\"A word-press.hu jelenleg szerve