--
-- Tábla szerkezet ehhez a táblához `wp01_posts`
--

DROP TABLE IF EXISTS `wp01_posts`;
CREATE TABLE IF NOT EXISTS `wp01_posts` (
  `ID` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `post_author` bigint UNSIGNED NOT NULL DEFAULT '0',
  `post_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_date_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content` longtext COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_title` text COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_excerpt` text COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_status` varchar(20) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'publish',
  `comment_status` varchar(20) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'open',
  `ping_status` varchar(20) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'open',
  `post_password` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `post_name` varchar(200) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `to_ping` text COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `pinged` text COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_modified` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_modified_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content_filtered` longtext COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_parent` bigint UNSIGNED NOT NULL DEFAULT '0',
  `guid` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `menu_order` int NOT NULL DEFAULT '0',
  `post_type` varchar(20) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'post',
  `post_mime_type` varchar(100) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `comment_count` bigint NOT NULL DEFAULT '0',
  PRIMARY KEY (`ID`),
  KEY `post_name` (`post_name`(191)),
  KEY `type_status_date` (`post_type`,`post_status`,`post_date`,`ID`),
  KEY `post_parent` (`post_parent`),
  KEY `post_author` (`post_author`)
) ENGINE=MyISAM AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;

--
-- A tábla adatainak kiíratása `wp01_posts`
--

INSERT INTO `wp01_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(1, 1, '2024-01-16 11:22:08', '2024-01-16 10:22:08', '<!-- wp:paragraph -->\n<p>Üdvözlet a WordPress-ben! Ez az első bejegyzés, amelyet lehet akár módosítani, akár törölni, aztán kezdődhet az írás, a tartalommal történő feltöltés.</p>\n<!-- /wp:paragraph -->', 'Helló Világ!', '', 'publish', 'open', 'open', '', 'hello-vilag', '', '', '2024-01-16 11:22:08', '2024-01-16 10:22:08', '', 0, 'http://localhost/szoft24b01/?p=1', 0, 'post', '', 1),
(2, 1, '2024-01-16 11:22:08', '2024-01-16 10:22:08', '<!-- wp:paragraph -->\n<p>Ez egy mintaoldal. Az oldal különbözik a bejegyzéstől annyiban, hogy az oldal egy állandó tartalmú bejegyzés, ami - a legtöbb sablonnál - a weboldal navigációs részében állandó helyen van.\nA legtöbb ember olyan Bemutatkozó oldallal kezd, amelyik bemutatja őt, vagy a tevékenységét a weboldal látogatóinak. A Bemutatkozás oldal valami ilyesmi lehet:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\"><p>Üdvözlet az Olvasóknak! Nappal biciklis pizzafutár vagyok, éjszaka pedig egy törekvő színész-tanonc, ez pedig az én weboldalam.<br>Budapesten élek és van egy csodálatos német juhász kutyám, aki Velorex névre hallgat. Kedvenc koktélom a Piña Colada, de a Mojitot is nagyon kedvelem. (De, azért az igazi nedű: egy bársonyos vörösbor.)</p></blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>…vagy valami egészen más:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\"><p>Az XYZ Bigyó Vállalatot 1971-ben alapították, azóta gyártja a legjobb minőségű bigyókat. A cég központja Budapesten található, ahol több mint 2000 embert foglalkoztatnak, valamint számos közösségi és jótékonysági programban is aktívan résztvesznek.</p></blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>Új WordPress felhasználóként a <a href=\"http://localhost/szoft24b01/wp-admin/\">Vezérlőpult</a> részre ugorva lehet törölni ezt az oldalt, és létrehozni egy úja oldalt a saját tartalmunk részére. Jó szórakozást!</p>\n<!-- /wp:paragraph -->', 'Ez egy minta oldal', '', 'publish', 'closed', 'open', '', 'ez-egy-minta-oldal', '', '', '2024-01-16 11:22:08', '2024-01-16 10:22:08', '', 0, 'http://localhost/szoft24b01/?page_id=2', 0, 'page', '', 0),
(3, 1, '2024-01-16 11:22:08', '2024-01-16 10:22:08', '<!-- wp:heading --><h2>Kik vagyunk</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>A weboldalunk címe: http://localhost/szoft24b01.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Hozzászólások</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>Hozzászólás beküldésekor a hozzászólási űrlapban megadottakon kívül begyűjtésre kerül a hozzászóló IP címe és a böngészőazonosító karakterlánc a kéretlen tartalmak kiszűrése céljából.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>Egy személytelenített, az e-mail címből előállított karakterlánc (hashnek szokás nevezni) kerül továbbításra a Gravatar szolgáltatás felé, ha ez az oldalon használatban van. A Gravatar szolgáltatás feltételei az alábbi címen tekinthetőek meg: https://automattic.com/privacy/. A hozzászólás elfogadása után, a hozzászólásunk tartalma és a profil képünk is megjelenik nyilvánosan.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Média</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>Amennyiben regisztrált felhasználó által kerül kép feltöltésre a honlapra, kerülni kell az az olyan EXIF-eket, amelyekben GPS pozíció adatok is szerepelnek. A honlap látogatói ezeket letölthetik és kinyerhetik a helyadatokat a honlapon található képekből.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Sütik</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>Ha hozzászólást írunk a honlapon, a megadott nevet, e-mail és honlap címet sütikben eltároljuk. A tárolás a kényelmi célokat szolgál azért, így a következő hozzászóláskor ezeket a mező adatokat nem kell kitölteni. A sütik lejárati ideje egy év.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>Ha ellátogatunk a bejelentkezési oldalra, akkor átmeneti sütiket állítunk be annak érdekében, hogy megállapítsuk, hogy a böngésző elfogadja-e a sütiket. Ezek a sütik nem tartalmaznak személyes információt, és törlődnek, ahogy bezárjuk a böngészőt.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>A honlapra történő bejelentkezéskor több sütit hozunk létre, amely elmenti a bejelentkezési információt és a szerkesztőfelület megjelenítési opcióit. A bejelentkezési sütik két napig érvényesek, a szerkesztőfelület képernyő opcióit tároló süti egy évig. Amennyiben az &quot;Emlékezz rám&quot; opciót bejelöljük, a bejelentkezés két hétig folytatódik. Kijelentkezéskor a bejelentkezési sütik eltávolításra kerülnek.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>Amennyiben bejegyzést vagy oldalt szerkesztünk, egy újabb sütit tárol el a böngészőnk. Ez a süti nem tartalmaz személyes adatot, egyszerűen csak a bejegyzés azonosító számát tárolja, amelyet szerkesztettünk. Egy nap múlva jár le az érvényessége.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Más honlapokról származó beágyazott tartalmak</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>A honlapon elérhető bejegyzések külső forrásból származó beágyazott tartalmakat (pl. videók, képek, cikkek stb.) használhatnak. A külső forrásból származó beágyazott tartalmak pontosan úgy viselkednek, mintha meglátogattunk volna egy másik honlapot.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>Ezek a webhelyek lehetséges, hogy adatot gyűjtenek a látogatókról, sütiket vagy harmadik féltől származó követőkódot használnak, figyelik a beágyazott tartalommal kapcsolatos felhasználói viselkedést, ha rendelkezünk felhasználói fiókkal és be vagyunk jelentkezve az oldalra.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Kivel osztjuk meg a felhasználói adatokat</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>Ha jelszó visszaállítást kér, akkor az IP-címet a visszaállító e-mail tartalmazni fogja.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Mennyi ideig őrizzük a személyes adatot</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>Ha hozzászólunk, a hozzászólás és annak metaadatai nem meghatározható ideig a rendszerben maradnak. Ennek célja, hogy az összes ezt követő bármely hozzászólás általunk megismertté és jóváhagyottá váljon, azaz ne kerüljön fel a moderálandó hozzászólások listájára.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>A honlapon regisztrált felhasználók (ha vannak ilyenek) személyes adatai a saját felhasználói profiljukban is tárolásra kerülnek. Minden felhasználó megtekintheti, szerkesztheti vagy törölheti a személyes adatait bármikor (kivéve, hogy nem változtathatja meg a saját felhasználónevét). A honlap rendszergazdái ezen információkat szintén megtekinthetik és szerkeszthetik.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Milyen jogokkal rendelkezik a felhasználó a saját adatai kapcsán</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>A weboldalon regisztrált fiók vagy hozzászólás írása esetén kérhető a személyes adatok export fájlban történő megküldése, amely bármilyen adatot tartalmaz, amit korábban a felhasználó rendelkezésünkre bocsátott. Kérhető továbbá, hogy bármilyen korábban megadott személyes adatot töröljük. Ez nem vonatkozik azokra az adatokra, amelyeket adminisztrációs, jogi vagy biztonsági okokból kötelező megőriznünk.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Where your data is sent</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Javasolt szöveg: </strong>A látogatók által beküldött hozzászólásokat automatikus spamszűrő szolgáltatás ellenőrizheti.</p><!-- /wp:paragraph -->', 'Adatkezelési tájékoztató', '', 'draft', 'closed', 'open', '', 'adatkezelesi-tajekoztato', '', '', '2024-01-16 11:22:08', '2024-01-16 10:22:08', '', 0, 'http://localhost/szoft24b01/?page_id=3', 0, 'page', '', 0),
